import React, { useState, useEffect } from 'react';
import { ref, onValue, getDatabase } from 'firebase/database';
import { initializeApp, getApps } from 'firebase/app';
import usePlayerStats from './usePlayerStats';

// Firebase configuration and connection
const getFirebaseApp = () => {
  const apps = getApps();
  if (apps.length > 0) {
    return apps[0];
  } else {
    const firebaseConfig = {
      apiKey: "AIzaSyAvITdQHZkF-Kjkacna0fsxPYqbBEKJwlg",
      authDomain: "fvwl-8109b.firebaseapp.com",
      databaseURL: "https://fvwl-8109b-default-rtdb.europe-west1.firebasedatabase.app",
      projectId: "fvwl-8109b",
      storageBucket: "fvwl-8109b.firebasestorage.app",
      messagingSenderId: "406636067359",
      appId: "1:406636067359:web:8b70673d38495254b2f32a"
    };
    return initializeApp(firebaseConfig);
  }
};

const app = getFirebaseApp();
const database = getDatabase(app);

const EnhancedSquadList = ({ isAuthenticated }) => {
  const [players, setPlayers] = useState([]);
  const [filteredPlayers, setFilteredPlayers] = useState([]);
  const [statusFilter, setStatusFilter] = useState('Squad');
  const [loading, setLoading] = useState(true);
  const [firebaseError, setFirebaseError] = useState(null);

  const {
    playerStats,
    loading: statsLoading,
    error: statsError,
    getPlayerAppearanceSummary,
    getPlayerDisciplinarySummary,
    getPlayerGoalSummary,
    totalFixtures
  } = usePlayerStats();

  useEffect(() => {
    const playersRef = ref(database, 'squad2526');
    const unsubscribe = onValue(playersRef, (snapshot) => {
      try {
        const data = snapshot.val();
        if (data) {
          const playersArray = Object.values(data);
          setPlayers(playersArray);
          console.log('Loaded players from Firebase:', playersArray.length);
        } else {
          setFirebaseError('No player data found in Firebase');
        }
        setLoading(false);
      } catch (error) {
        console.error('Error processing Firebase data:', error);
        setFirebaseError('Error loading player data');
        setLoading(false);
      }
    }, (error) => {
      console.error('Firebase connection error:', error);
      setFirebaseError('Cannot connect to Firebase: ' + error.message);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const filtered = players.filter(player => {
      if (statusFilter === 'All') return true;
      return player.notes === statusFilter;
    });
    setFilteredPlayers(filtered);
  }, [players, statusFilter]);

  const calculateTotals = () => {
    if (!isAuthenticated || !filteredPlayers.length) return { total: 0, bonusesTotal: 0 };

    return filteredPlayers.reduce((totals, player) => ({
      total: totals.total + (parseFloat(player.overallTotal) || 0),
      bonusesTotal: totals.bonusesTotal + (parseFloat(player.bonuses) || 0)
    }), { total: 0, bonusesTotal: 0 });
  };

  const totals = calculateTotals();
  const statusOptions = ['All', 'Squad', 'On loan', 'Loan in', 'Gone'];

  if (loading || statsLoading) {
    return (
      <div className="min-h-screen bg-gray-100 p-4">
        <div className="max-w-4xl mx-auto">
          <h1 className="text-3xl font-bold mb-6">Squad 2025/26</h1>
          <div className="text-center">Loading squad and statistics...</div>
        </div>
      </div>
    );
  }

  if (firebaseError || statsError) {
    return (
      <div className="min-h-screen bg-gray-100 p-4">
        <div className="max-w-4xl mx-auto">
          <h1 className="text-3xl font-bold mb-6">Squad 2025/26</h1>
          <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mb-4">
            <strong>Error loading data:</strong>
            {firebaseError && <div>Firebase: {firebaseError}</div>}
            {statsError && <div>Statistics: {statsError}</div>}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 p-4">
      <div className="max-w-7xl mx-auto">
        <h1 className="text-2xl sm:text-3xl font-bold mb-6">Squad 2025/26</h1>

        {/* Statistics Summary */}
        <div className="bg-white rounded-lg shadow-md p-4 sm:p-6 mb-6">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-2 sm:gap-4 text-center">
            <div>
              <div className="text-xl sm:text-3xl font-bold text-blue-600">{totalFixtures || 0}</div>
              <div className="text-xs sm:text-sm text-gray-600">Fixtures Played</div>
            </div>
            <div>
              <div className="text-xl sm:text-3xl font-bold text-green-600">{playerStats.length || 0}</div>
              <div className="text-xs sm:text-sm text-gray-600">Players Used</div>
            </div>
            <div>
              <div className="text-xl sm:text-3xl font-bold text-purple-600">{filteredPlayers.length}</div>
              <div className="text-xs sm:text-sm text-gray-600">In Current View</div>
            </div>
            <div>
              <div className="text-xl sm:text-3xl font-bold text-orange-600">
                {playerStats.filter(p => p.totalAppearances >= 10).length || 0}
              </div>
              <div className="text-xs sm:text-sm text-gray-600">Regular Players (10+ apps)</div>
            </div>
          </div>
        </div>

        {/* Status Filter Buttons */}
        <div className="flex flex-wrap gap-2 sm:gap-3 mb-6">
          {statusOptions.map(status => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-3 sm:px-6 py-2 sm:py-3 rounded-lg font-medium transition-colors shadow-sm text-sm sm:text-base ${
                statusFilter === status
                  ? 'bg-blue-600 text-white shadow-md'
                  : 'bg-white text-gray-700 border border-gray-300 hover:bg-gray-50'
              }`}
            >
              {status}
            </button>
          ))}
        </div>

        {/* Financial Totals for Authenticated Users */}
        {isAuthenticated && (
          <div className="bg-green-50 border border-green-200 rounded-lg p-4 sm:p-6 mb-6">
            <h3 className="font-semibold text-green-800 mb-3">Financial Summary ({statusFilter})</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="bg-white p-4 rounded">
                <div className="text-xl sm:text-2xl font-bold text-green-600">£{totals.total.toLocaleString()}</div>
                <div className="text-sm text-gray-600">Overall Total</div>
              </div>
              <div className="bg-white p-4 rounded">
                <div className="text-xl sm:text-2xl font-bold text-green-600">£{totals.bonusesTotal.toLocaleString()}</div>
                <div className="text-sm text-gray-600">Bonuses Total</div>
              </div>
            </div>
          </div>
        )}

        {/* Debug Info */}
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 mb-6 text-sm">
          <strong>Debug Info:</strong> 
          <div>Players from Firebase: {players.length}</div>
          <div>Filtered players: {filteredPlayers.length}</div>
          <div>Player stats calculated: {playerStats.length}</div>
        </div>

        {/* Players Grid */}
        <div className="grid gap-4 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
          {filteredPlayers.map(player => {
            const fullName = `${player.forename} ${player.surname}`;

            const appearanceStats = getPlayerAppearanceSummary ? 
              getPlayerAppearanceSummary(fullName) : 
              { total: 0, starts: 0, substitutes: 0, starterPercentage: 0 };

            const disciplinaryStats = getPlayerDisciplinarySummary ? 
              getPlayerDisciplinarySummary(fullName) : 
              { yellow: 0, red: 0, total: 0 };

            const goalStats = getPlayerGoalSummary ? 
              getPlayerGoalSummary(fullName) : 
              { total: 0, league: 0, fACup: 0, eFLCup: 0, eFLTrophy: 0 };

            return (
              <div
                key={player.id}
                className="bg-white rounded-lg shadow-md p-4 sm:p-6 hover:shadow-lg transition-shadow cursor-pointer border border-gray-200"
              >
                {/* Player Header */}
                <div className="mb-4">
                  <h3 className="text-lg sm:text-xl font-bold text-gray-900">
                    {player.forename} {player.surname}
                  </h3>
                  <div className="flex justify-between items-center text-sm text-gray-600 mt-1">
                    <span>{player.notes}</span>
                    <span className="bg-gray-100 px-2 py-1 rounded text-xs sm:text-sm">
                      Rating: {player.rating}/10
                    </span>
                  </div>
                </div>

                {/* Mobile Debug - Add this above the statistics grid */}
<div style={{backgroundColor: 'red', color: 'white', padding: '10px', margin: '10px 0', fontSize: '16px'}}>
  DEBUG: Stats section loading...
  <br />Goals: {goalStats.total}
  <br />Apps: {appearanceStats.total}
  <br />Cards: {disciplinaryStats.total}
</div>

                {/* Statistics Grid - Simple Mobile Version */}
<div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', fontSize: '14px'}}>
  {/* Goals */}
  <div style={{backgroundColor: '#dbeafe', padding: '12px', borderRadius: '8px', textAlign: 'center', border: '2px solid blue'}}>
    <div style={{fontWeight: 'bold', color: '#1e40af'}}>Goals</div>
    <div style={{fontSize: '24px', fontWeight: 'bold', color: '#1e40af', margin: '8px 0'}}>
      {goalStats.total}
    </div>
    <div style={{fontSize: '12px', color: '#6b7280'}}>
      L: {goalStats.league} | C: {goalStats.fACup + goalStats.eFLCup + goalStats.eFLTrophy}
    </div>
  </div> 

                  {/* Appearances */}
  <div style={{backgroundColor: '#dcfce7', padding: '12px', borderRadius: '8px', textAlign: 'center', border: '2px solid green'}}>
    <div style={{fontWeight: 'bold', color: '#166534'}}>Apps</div>
    <div style={{fontSize: '24px', fontWeight: 'bold', color: '#166534', margin: '8px 0'}}>
      {appearanceStats.total}
    </div>
    <div style={{fontSize: '12px', color: '#6b7280'}}>
      {appearanceStats.starts}S / {appearanceStats.substitutes}Sub
    </div>
  </div>

                  {/* Starter % */}
  <div style={{backgroundColor: '#f3e8ff', padding: '12px', borderRadius: '8px', textAlign: 'center', border: '2px solid purple'}}>
    <div style={{fontWeight: 'bold', color: '#7c3aed'}}>Starter %</div>
    <div style={{fontSize: '24px', fontWeight: 'bold', color: '#7c3aed', margin: '8px 0'}}>
      {appearanceStats.starterPercentage}%
    </div>
    <div style={{fontSize: '12px', color: '#6b7280'}}>
      {appearanceStats.starts} starts
    </div>
  </div>


                   {/* Cards */}
  <div style={{backgroundColor: '#fefce8', padding: '12px', borderRadius: '8px', textAlign: 'center', border: '2px solid orange'}}>
    <div style={{fontWeight: 'bold', color: '#ca8a04'}}>Cards</div>
    <div style={{fontSize: '24px', fontWeight: 'bold', color: '#ca8a04', margin: '8px 0'}}>
      {disciplinaryStats.total}
    </div>
    <div style={{fontSize: '12px', color: '#6b7280'}}>
      {disciplinaryStats.yellow}Y / {disciplinaryStats.red}R
    </div>
  </div>
</div>

                {/* Financial Info */}
                {isAuthenticated && (
                  <div className="mt-4 pt-4 border-t border-gray-200">
                    <div className="grid grid-cols-1 gap-2 text-sm">
                      <div className="flex justify-between">
                        <span className="font-medium text-gray-700">Weekly:</span> 
                        <span className="text-gray-900">£{player.currentWeeklyWage?.toLocaleString() || '0'}</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="font-medium text-gray-700">Total:</span> 
                        <span className="text-gray-900 font-semibold">£{player.overallTotal?.toLocaleString() || '0'}</span>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {filteredPlayers.length === 0 && (
          <div className="text-center py-12">
            <div className="text-gray-500 text-lg">No players found for the selected filter.</div>
            <div className="text-gray-400 text-sm mt-2">
              Try selecting "All" to see all players, or check that players exist in Firebase.
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default EnhancedSquadList;
